mapper.sql:
SELECT
ID,
COMPANY_ID,
COMPANY_NAME,
OPEN_ACCOUNT_BANK,
BANK_CODE,
BANK_NAME,
BANK_NAME_ENGLISH,
BANK_NUMBER,
BANK_TYPE_CODE,
BANK_TYPE_NAME,
BANK_ACCOUNT_CODE,
BANK_ACCOUNT_NAME,
CURRENCY_CODE,
CURRENCY_NAME,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_FD_BANK_PAY


        and ID = #{id}


        and COMPANY_ID = #{companyId}


        and COMPANY_NAME = #{companyName}



        and OPEN_ACCOUNT_BANK LIKE #{openAB}


        and BANK_CODE = #{bankCode}


        and BANK_NAME = #{bankName}






        and BANK_NAME_ENGLISH = #{bankNameEnglish}



        and BANK_NUMBER LIKE #{bankNm}


        and BANK_TYPE_CODE = #{bankTypeCode}


        and BANK_TYPE_NAME = #{bankTypeName}


        and BANK_ACCOUNT_CODE = #{bankAccountCode}


        and BANK_ACCOUNT_NAME = #{bankAccountName}


        and CURRENCY_CODE = #{currencyCode}


        and CURRENCY_NAME = #{currencyName}
